local LBattleBuffActBase = require("LApp.gameplay.videobattle.view.buffact.LBattleBuffActBase")
---@class LBattleBuffActRoleAct:LBattleBuffActBase
local LBattleBuffActRoleAct = classX("LBattleBuffActRoleAct",LBattleBuffActBase)

function LBattleBuffActRoleAct:ctor(viewMgr)
    LBattleBuffActBase.ctor(self, viewMgr)
    self._type = LSkillEffConst.PLAY_EFF_ANI
end

function LBattleBuffActRoleAct:Preload()

end

function LBattleBuffActRoleAct:OnStart()
    local obj = self._runningData.targetObj

    obj:SetSkillPlaying(true)

    local effData = self._effData
    --动作名字
    local ani = effData.effRes
    --动作时间
    local time = effData.playTime
    time = effData.actionReset == 0 and time or 0
    --Ninfo(string.format("play ani %s,time %s",ani,time))
    obj:PlayAni(ani, false, time)

    local soundName = effData.soundBattle
    if not string.isempty(soundName) then
        LxUiHelper.PlaySoundByName(soundName)
    end


end



return LBattleBuffActRoleAct